parameters.jsCode:
const formData = $input.first().json;
const binaryData = $input.first().binary;

const fs = require('fs');
const http = require('http');

let fileBuffer;

// Try to get file from form
if (binaryData) {
  const fieldName = Object.keys(binaryData)[0];
  const fileData = binaryData[fieldName];
  const tempBuffer = Buffer.from(fileData.data, 'base64');

  if (tempBuffer.length > 100) {
    // Real file received
    fileBuffer = tempBuffer;
    fs.writeFileSync('/tmp/current_cv.pdf', fileBuffer);
  } else {
    // n8n truncated the file - read from disk
    fileBuffer = fs.readFileSync('/tmp/current_cv.pdf');
  }
} else {
  fileBuffer = fs.readFileSync('/tmp/current_cv.pdf');
}

const body = JSON.stringify({ base64: fileBuffer.toString('base64') });

const rawResponse = await new Promise((resolve, reject) => {
  const req = http.request({
    hostname: 'localhost',
    port: 3001,
    path: '/extract',
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Content-Length': Buffer.byteLength(body)
    }
  }, (res) => {
    let data = '';
    res.on('data', chunk => data += chunk);
    res.on('end', () => resolve(data));
  });
  req.on('error', reject);
  req.write(body);
  req.end();
});

const result = JSON.parse(rawResponse);
const cvText = result.text || '';

return [{
  json: {
    full_name: formData.full_name || formData['Full Name'] || 'Unknown',
    email: formData.email || '',
    github: formData.github || '',
    cv_text: cvText.substring(0, 8000),
    char_count: cvText.length,
    pages: result.pages || 1,
    source: 'CV'
  }
}];

// Get data from webhook body
const body = $input.first().json.body || $input.first().json;

const userName = body['Votre nom complet'] || body.user_name || "Anonymous";

// Extract question responses (Q1-Q18)
const q1  = Number(body.q1  || body['Q1']  || 0);
const q2  = Number(body.q2  || body['Q2']  || 0);
const q3  = Number(body.q3  || body['Q3']  || 0);
const q4  = Number(body.q4  || body['Q4']  || 0);
const q5  = Number(body.q5  || body['Q5']  || 0);
const q6  = Number(body.q6  || body['Q6']  || 0);
const q7  = Number(body.q7  || body['Q7']  || 0);
const q8  = Number(body.q8  || body['Q8']  || 0);
const q9  = Number(body.q9  || body['Q9']  || 0);
const q10 = Number(body.q10 || body['Q10'] || 0);
const q11 = Number(body.q11 || body['Q11'] || 0);
const q12 = Number(body.q12 || body['Q12'] || 0);
const q13 = Number(body.q13 || body['Q13'] || 0);
const q14 = Number(body.q14 || body['Q14'] || 0);
const q15 = Number(body.q15 || body['Q15'] || 0);
const q16 = Number(body.q16 || body['Q16'] || 0);
const q17 = Number(body.q17 || body['Q17'] || 0);
const q18 = Number(body.q18 || body['Q18'] || 0);

// Calculate scores
const scores = {
  communication: Math.round((q1 + q2 + q3) / 3 * 10) / 10,
  discipline:    Math.round((q4 + q5 + q6) / 3 * 10) / 10,
  curiosity:     Math.round((q7 + q8 + q9) / 3 * 10) / 10,
  collaboration: Math.round((q10 + q11 + q12) / 3 * 10) / 10,
  ownership:     Math.round((q13 + q14 + q15) / 3 * 10) / 10,
  leadership:    Math.round((q16 + q17 + q18) / 3 * 10) / 10
};

const overall = Math.round(
  Object.values(scores).reduce((a, b) => a + b, 0) / 6 * 10
) / 10;

const skillsArray = Object.entries(scores).map(([skill, score]) => ({ skill, score }));
skillsArray.sort((a, b) => b.score - a.score);

const result = {
  user_name: userName,
  timestamp: new Date().toISOString(),
  soft_skills: {
    communication: { score: scores.communication, evidence: "Self-assessment via PCM test" },
    discipline:    { score: scores.discipline,    evidence: "Self-assessment via PCM test" },
    curiosity:     { score: scores.curiosity,     evidence: "Self-assessment via PCM test" },
    collaboration: { score: scores.collaboration, evidence: "Self-assessment via PCM test" },
    ownership:     { score: scores.ownership,     evidence: "Self-assessment via PCM test" },
    leadership:    { score: scores.leadership,    evidence: "Self-assessment via PCM test" }
  },
  overall_score: overall,
  top_strength: skillsArray[0].skill,
  main_weakness: skillsArray[skillsArray.length - 1].skill,
  source: "PCM",
  raw_responses: { q1,q2,q3,q4,q5,q6,q7,q8,q9,q10,q11,q12,q13,q14,q15,q16,q17,q18 }
};

return [{ json: result }];

const body = $input.first().json.body || $input.first().json;
const binaryData = $input.first().binary;

const userName = body.full_name || 'Unknown';
const userEmail = body.email || '';
const githubUsername = body.github_username || '';

const http = require('http');
const fs = require('fs');

function httpPost(path, data) {
  return new Promise((resolve, reject) => {
    const reqBody = JSON.stringify(data);
    const req = http.request({
      hostname: 'localhost',
      port: 5678,
      path: path,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(reqBody)
      }
    }, (res) => {
      let d = '';
      res.on('data', chunk => d += chunk);
      res.on('end', () => {
        try { resolve(JSON.parse(d)); }
        catch(e) { resolve({error: d}); }
      });
    });
    req.on('error', reject);
    req.write(reqBody);
    req.end();
  });
}

// STEP 1 — Extract CV text from PDF
let cvAnalysis = {
  soft_skills: {
    communication: {score: 7, evidence: 'CV not provided'},
    discipline:    {score: 7, evidence: 'CV not provided'},
    curiosity:     {score: 7, evidence: 'CV not provided'},
    collaboration: {score: 7, evidence: 'CV not provided'},
    ownership:     {score: 7, evidence: 'CV not provided'},
    leadership:    {score: 7, evidence: 'CV not provided'}
  },
  overall_score: 7,
  source: 'CV'
};

if (binaryData && Object.keys(binaryData).length > 0) {
  try {
    const fieldName = Object.keys(binaryData)[0];
    const fileData = binaryData[fieldName];
    const pdfBuffer = Buffer.from(fileData.data, 'base64');
    fs.writeFileSync('/tmp/master_cv.pdf', pdfBuffer);
    const fileBuffer = fs.readFileSync('/tmp/master_cv.pdf');

    const extractBody = JSON.stringify({ base64: fileBuffer.toString('base64') });
    const cvText = await new Promise((resolve, reject) => {
      const req = http.request({
        hostname: 'localhost', port: 3001, path: '/extract',
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Content-Length': Buffer.byteLength(extractBody)
        }
      }, (res) => {
        let d = '';
        res.on('data', c => d += c);
        res.on('end', () => {
          try { resolve(JSON.parse(d)); }
          catch(e) { resolve({text: ''}); }
        });
      });
      req.on('error', () => resolve({text: ''}));
      req.write(extractBody);
      req.end();
    });

    if (cvText.text && cvText.text.length > 50) {
      const cvResult = await httpPost('/webhook/cv-upload-text', {
        full_name: userName,
        cv_text: cvText.text
      });
      if (cvResult && cvResult.soft_skills) {
        cvAnalysis = cvResult;
        cvAnalysis.source = 'CV';
      }
    }
  } catch(e) {
    cvAnalysis.error = e.message;
  }
}

// STEP 2 — GitHub Analysis
let githubAnalysis = {
  soft_skills: {
    communication: {score: 5, evidence: 'No GitHub provided'},
    discipline:    {score: 5, evidence: 'No GitHub provided'},
    curiosity:     {score: 5, evidence: 'No GitHub provided'},
    collaboration: {score: 5, evidence: 'No GitHub provided'},
    ownership:     {score: 5, evidence: 'No GitHub provided'},
    leadership:    {score: 5, evidence: 'No GitHub provided'}
  },
  overall_score: 5,
  source: 'GitHub'
};

if (githubUsername) {
  try {
    const ghResult = await httpPost('/webhook/github-analyze', {
      github_username: githubUsername
    });
    if (ghResult && !ghResult.error) {
      githubAnalysis = ghResult;
      githubAnalysis.source = 'GitHub';
    }
  } catch(e) {
    githubAnalysis.error = e.message;
  }
}

// STEP 3 — PCM scores from form
// ✅ FIX: correction de la syntaxe communication + evidence ajouté
const pcmResult = {
  soft_skills: {
    communication: {score: Math.round((Number(body.q1||5)+Number(body.q2||5)+Number(body.q3||5))/3*10)/10,  evidence: 'Self-assessment PCM'},
    discipline:    {score: Math.round((Number(body.q4||5)+Number(body.q5||5)+Number(body.q6||5))/3*10)/10,  evidence: 'Self-assessment PCM'},
    curiosity:     {score: Math.round((Number(body.q7||5)+Number(body.q8||5)+Number(body.q9||5))/3*10)/10,  evidence: 'Self-assessment PCM'},
    collaboration: {score: Math.round((Number(body.q10||5)+Number(body.q11||5)+Number(body.q12||5))/3*10)/10, evidence: 'Self-assessment PCM'},
    ownership:     {score: Math.round((Number(body.q13||5)+Number(body.q14||5)+Number(body.q15||5))/3*10)/10, evidence: 'Self-assessment PCM'},
    leadership:    {score: Math.round((Number(body.q16||5)+Number(body.q17||5)+Number(body.q18||5))/3*10)/10, evidence: 'Self-assessment PCM'}
  },
  overall_score: Math.round((
    Number(body.q1||5)+Number(body.q2||5)+Number(body.q3||5)+
    Number(body.q4||5)+Number(body.q5||5)+Number(body.q6||5)+
    Number(body.q7||5)+Number(body.q8||5)+Number(body.q9||5)+
    Number(body.q10||5)+Number(body.q11||5)+Number(body.q12||5)+
    Number(body.q13||5)+Number(body.q14||5)+Number(body.q15||5)+
    Number(body.q16||5)+Number(body.q17||5)+Number(body.q18||5)
  )/18*10)/10,
  source: 'PCM'
};

// STEP 4 — Weighted merge
const weights = { cv: 0.4, github: 0.3, pcm: 0.3 };

function getScore(analysis, skill) {
  return analysis?.soft_skills?.[skill]?.score || 5;
}

function weightedScore(skill) {
  const cv  = getScore(cvAnalysis, skill);
  const gh  = getScore(githubAnalysis, skill);
  const pcm = getScore(pcmResult, skill);
  return Math.round((cv*weights.cv + gh*weights.github + pcm*weights.pcm) * 10) / 10;
}

const mergedScores = {
  communication: weightedScore('communication'),
  discipline:    weightedScore('discipline'),
  curiosity:     weightedScore('curiosity'),
  collaboration: weightedScore('collaboration'),
  ownership:     weightedScore('ownership'),
  leadership:    weightedScore('leadership')
};

const overallScore = Math.round(
  Object.values(mergedScores).reduce((a,b) => a+b, 0) / 6 * 10
) / 10;

const skillsArray = Object.entries(mergedScores)
  .map(([skill, score]) => ({skill, score}))
  .sort((a,b) => b.score - a.score);

// ✅ FIX: source_data retourne les scores simples pour l'affichage frontend
return [{
  json: {
    user_name:          userName,
    user_email:         userEmail,
    github_username:    githubUsername,
    timestamp:          new Date().toISOString(),
    merged_soft_skills: mergedScores,
    overall_score:      overallScore,
    top_3_strengths:    skillsArray.slice(0,3).map(s => s.skill),
    top_3_weaknesses:   skillsArray.slice(-3).map(s => s.skill).reverse(),
    source_data: {
      cv:     { overall_score: cvAnalysis.overall_score     || 7 },
      github: { overall_score: githubAnalysis.overall_score || 5 },
      pcm:    { overall_score: pcmResult.overall_score      || 5 }
    },
    weights_applied: weights
  }
}];

